sequence.script:
function value(name, fallback) {
    var current = mc.getProperty(name);
    return current == null || String(current).length === 0
        ? fallback
        : String(current);
}

mc.setPayloadJSON({
    type: 'https://demo.telco/errors/integration-failure',
    title: 'Secure transaction risk assessment failed',
    status: 500,
    detail: value('ERROR_MESSAGE', 'Unexpected integration runtime failure'),
    correlationId: value('correlation.id', ''),
    integrationErrorCode: value('ERROR_CODE', 'MI-UNEXPECTED')
});
